1	//! The `sync` subcommand: fetch + classify + (optionally) rebase /
2	//! fast-forward a workspace's repos against their remotes.
3	//!
4	//! Default is `--check` (fetch + report, error if any repo needs
5	//! action); `--no-check` applies. On any failure every repo is
6	//! reverted to its pre-sync op via `jj op restore`.
7	//!
8	//! `current_op_id` / `op_restore` are `pub(crate)` so `push` reuses
9	//! the same snapshot-and-restore pattern.
10	
11	use std::path::{Path, PathBuf};
12	use std::process::Command;
13	
14	use clap::Args;
15	use log::{LevelFilter, debug, info, warn};
16	
17	use crate::common::{default_scope, find_workspace_root, run, scope_to_repos};
18	use crate::context::Context;
19	use crate::options_flags::scope::{Scope, parse_scope};
20	use crate::subcommand::SubcommandRunner;
21	
22	/// Fetch and sync a set of repos to their remotes.
23	///
24	/// Default is `--check`: fetch + classify + report, **error** if any
25	/// repo is `behind` or `diverged`. Pass `--no-check` to actually
26	/// rebase / fast-forward. On any failure the starting state of every
27	/// repo is restored via `jj op restore`.
28	///
29	/// Scripts and automation should pass `--check` or `--no-check`
30	/// explicitly rather than relying on the default — defaults can shift,
31	/// explicit flags lock in the contract.
32	///
33	/// Repo set is resolved from `-R/--repo` + `--scope`:
34	///
35	/// - `-R PATH` — workspace root, or a single repo to sync alone.
36	/// - `--scope=code|bot|code,bot` — keyword role selection,
37	///   resolved via the workspace root's `.vc-config.toml`.
38	/// - Neither — workspace-default scope:
39	///   - dual workspace (`.vc-config.toml` with `other-repo`) → `code,bot`
40	///   - single-repo workspace (`.vc-config.toml`, no `other-repo`) → `code`
41	///   - POR (no `.vc-config.toml`) → cwd
42	#[derive(Args, Debug)]
43	pub struct SyncArgs {
44	    /// Verify only — fetch + classify; error if any repo needs action.
45	    /// This is the default; pass explicitly in scripts.
46	    #[arg(long, conflicts_with = "no_check")]
47	    pub check: bool,
48	
49	    /// Apply — fetch + classify, then rebase / fast-forward as needed.
50	    #[arg(long, conflicts_with = "check")]
51	    pub no_check: bool,
52	
53	    /// Suppress all informational output (exit code signals result)
54	    #[arg(short, long)]
55	    pub quiet: bool,
56	
57	    /// Bookmark to sync in each repo
58	    #[arg(long, default_value = "main")]
59	    pub bookmark: String,
60	
61	    /// Remote to sync against
62	    #[arg(long, default_value = "origin")]
63	    pub remote: String,
64	
65	    /// Workspace root, or a single jj repo to sync on its own.
66	    ///
67	    /// - `-R PATH` alone — sync just the repo at PATH.
68	    /// - `-R PATH -s ROLES` — use PATH as the workspace root and
69	    ///   sync the named side(s).
70	    #[arg(short = 'R', long = "repo", value_name = "PATH", verbatim_doc_comment)]
71	    pub repo: Option<PathBuf>,
72	
73	    /// Which repo(s) of the workspace to sync.
74	    ///
75	    /// `SCOPE=code|bot|code,bot`:
76	    ///
77	    /// - `code` — sync only the app repo.
78	    /// - `bot` — sync only the bot repo (errors if no bot repo
79	    ///   is configured).
80	    /// - `code,bot` — sync both repos.
81	    ///
82	    /// Composes with `-R` as the workspace root. Default depends
83	    /// on workspace state: dual workspace → `code,bot`;
84	    /// single-repo workspace or POR → `code`.
85	    #[arg(
86	        short = 's',
87	        long,
88	        value_name = "SCOPE",
89	        value_parser = parse_scope,
90	        verbatim_doc_comment
91	    )]
92	    pub scope: Option<Scope>,
93	}
94	
95	/// Inputs to the sync op, flat, owned, clap-free.
96	///
97	/// - `quiet`: `-q` / `--quiet` — clamp output to `Warn` for the run.
98	/// - `bookmark`: bookmark to sync in each repo (default `main`).
99	/// - `remote`: remote to sync against (default `origin`).
100	/// - `no_check`: `--no-check` — actually rebase / fast-forward
101	///   (absent ⇒ check mode: fetch + report only). The `--check`
102	///   flag is the explicit form of the default and carries no
103	///   value of its own, so it isn't mirrored here.
104	/// - `repo`: `-R/--repo` path (None ⇒ discover the workspace
105	///   root from cwd).
106	/// - `scope`: `--scope` parsed (None ⇒ resolve via the
107	///   workspace-default scope at run time).
108	pub struct SyncParams {
109	    pub quiet: bool,
110	    pub bookmark: String,
111	    pub remote: String,
112	    pub no_check: bool,
113	    pub repo: Option<PathBuf>,
114	    pub scope: Option<Scope>,
115	}
116	
117	impl From<&SyncArgs> for SyncParams {
118	    /// Convert clap-derived `SyncArgs` into the flat `SyncParams`.
119	    /// `--check` is dropped — it's the explicit form of the
120	    /// default; the op only ever consults `no_check`.
121	    fn from(a: &SyncArgs) -> Self {
122	        Self {
123	            quiet: a.quiet,
124	            bookmark: a.bookmark.clone(),
125	            remote: a.remote.clone(),
126	            no_check: a.no_check,
127	            repo: a.repo.clone(),
128	            scope: a.scope.clone(),
129	        }
130	    }
131	}
132	
133	impl SubcommandRunner for SyncArgs {
134	    type Params = SyncParams;
135	
136	    /// Delegate to the existing `From<&SyncArgs>` impl above
137	    /// (total — never fails).
138	    fn to_params(&self) -> Result<Self::Params, String> {
139	        Ok(SyncParams::from(self))
140	    }
141	
142	    /// Run the existing `sync` op.
143	    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
144	        sync(ctx, params)
145	    }
146	}
147	
148	/// Resolve `params` into the concrete repo list `sync_repos`
149	/// operates on.
150	///
151	/// `-R` and `--scope` compose:
152	///
153	/// - neither — workspace-default scope against the discovered root.
154	/// - `-R PATH` alone — sync just that repo.
155	/// - `-s ROLES` alone — roles against the discovered workspace root.
156	/// - `-R PATH -s ROLES` — roles against `PATH` as the workspace root.
157	fn resolve_params_to_repos(
158	    params: &SyncParams,
159	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
160	    match (&params.repo, &params.scope) {
161	        (None, None) => {
162	            let root = find_workspace_root();
163	            scope_to_repos(&default_scope(root.as_deref()), root.as_deref())
164	        }
165	        (Some(p), None) => Ok(vec![p.clone()]),
166	        (None, Some(s)) => scope_to_repos(s, find_workspace_root().as_deref()),
167	        (Some(p), Some(s)) => scope_to_repos(s, Some(p)),
168	    }
169	}
170	
171	/// Relationship between a local bookmark and its remote counterpart.
172	#[derive(Debug, Clone, PartialEq, Eq)]
173	pub enum State {
174	    /// Local and remote point at the same commit.
175	    UpToDate,
176	    /// Local is a strict ancestor of remote — fast-forward possible.
177	    Behind { local: String, remote: String },
178	    /// Remote is a strict ancestor of local — nothing to pull in.
179	    Ahead { local: String, remote: String },
180	    /// Neither is an ancestor of the other — needs rebase.
181	    Diverged { local: String, remote: String },
182	    /// The bookmark has no `@<remote>` counterpart.
183	    NoRemote,
184	}
185	
186	/// Per-repo context accumulated between the snapshot and action phases.
187	#[derive(Debug)]
188	struct RepoCtx {
189	    path: PathBuf,
190	    #[allow(dead_code)]
191	    op_id: String,
192	    state: State,
193	}
194	
195	/// CLI entry point for the `sync` subcommand.
196	///
197	/// Thin wrapper over `sync_repos` that resolves `--scope` into a
198	/// concrete repo list (falling back to the workspace-default
199	/// scope) and forwards the rest. Tests call `sync_repos` directly
200	/// with absolute fixture paths. `ctx` is unused today — present
201	/// for the uniform subcommand-layer signature.
202	///
203	/// When `--quiet` is set, the global log filter is temporarily
204	/// clamped to `Warn` for the duration of the call and restored on
205	/// return, so `info!` calls throughout sync (plus any
206	/// subprocess-stderr routed through `common::run`) go dark. Errors
207	/// still surface at `Warn` / `Error` so script callers don't lose
208	/// diagnostics.
209	pub fn sync(_ctx: &Context, params: &SyncParams) -> Result<(), Box<dyn std::error::Error>> {
210	    let repos = resolve_params_to_repos(params)?;
211	    if params.quiet {
212	        let prev = log::max_level();
213	        log::set_max_level(LevelFilter::Warn);
214	        let result = sync_repos(&repos, params);
215	        log::set_max_level(prev);
216	        result
217	    } else {
218	        sync_repos(&repos, params)
219	    }
220	}
221	
222	/// Sync the given repos against their remotes.
223	///
224	/// Orchestrates the full flow: pre-flight clean-check on every repo,
225	/// snapshot each repo's current op id, then hand off to `run_plan` for
226	/// fetch + classify + (optional) act. On any error, revert every repo
227	/// to its snapshot op via `jj op restore` so the caller sees an atomic
228	/// "either it all went through or nothing changed" outcome.
229	///
230	/// Paths may be relative (resolved against the process cwd) or
231	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
232	/// under parallel `cargo test`.
233	pub fn sync_repos(
234	    repos: &[PathBuf],
235	    params: &SyncParams,
236	) -> Result<(), Box<dyn std::error::Error>> {
237	    debug!(
238	        "sync: enter (no_check={}, bookmark={}, remote={})",
239	        params.no_check, params.bookmark, params.remote
240	    );
241	
242	    // Preflight: verify bookmark tracking on every repo before any
243	    // fetch/rebase. Implements "Non-tracking-remote bookmark detection"
244	    // — design at:
245	    //   https://github.com/winksaville/vc-x1/blob/main/notes/chores/chores-06.md#non-tracking-remote-bookmark-detection-design
246	    for repo in repos {
247	        crate::common::verify_tracking(repo, &params.bookmark)?;
248	    }
249	
250	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
251	    for repo in repos {
252	        let op_id = current_op_id(repo)?;
253	        debug!("{}: op snapshot = {op_id}", repo.display());
254	        snapshots.push((repo.clone(), op_id));
255	    }
256	
257	    let result = run_plan(&snapshots, params);
258	
259	    if let Err(e) = &result {
260	        warn!("sync failed: {e}");
261	        warn!("reverting all repos to starting state...");
262	        for (repo, op_id) in &snapshots {
263	            match op_restore(repo, op_id) {
264	                Ok(()) => info!("  {}: reverted to op {op_id}", repo.display()),
265	                Err(re) => warn!("  {}: revert failed: {re}", repo.display()),
266	            }
267	        }
268	    }
269	
270	    debug!("sync: exit");
271	    result
272	}
273	
274	/// Fetch and classify each repo, then act (or not, in dry-run).
275	///
276	/// Returns `Err` on the first failure so the caller can trigger the
277	/// cross-repo revert; partial success across repos is *not* a valid
278	/// end state for this command.
279	fn run_plan(
280	    snapshots: &[(PathBuf, String)],
281	    params: &SyncParams,
282	) -> Result<(), Box<dyn std::error::Error>> {
283	    // Phase 1 — fetch + classify silently.
284	    //
285	    // Each repo's fetch stderr is captured (rather than streamed to
286	    // `info!` via `common::run`) so we can decide after classification
287	    // whether to surface it. `jj git fetch`'s routine "Nothing
288	    // changed." chatter is the main thing we're suppressing here —
289	    // if nothing needs action, the user shouldn't see it.
290	    let mut fetched: Vec<(PathBuf, String)> = Vec::new();
291	    let mut ctxs: Vec<RepoCtx> = Vec::new();
292	    for (repo, op_id) in snapshots {
293	        let stderr = fetch_silent(repo, &params.remote)?;
294	        fetched.push((repo.clone(), stderr));
295	        let state = classify(repo, &params.bookmark, &params.remote)?;
296	        ctxs.push(RepoCtx {
297	            path: repo.clone(),
298	            op_id: op_id.clone(),
299	            state,
300	        });
301	    }
302	
303	    let any_action_needed = ctxs
304	        .iter()
305	        .any(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }));
306	
307	    // Phase 2 — emit status. `--quiet` is enforced globally via the
308	    // log-level clamp in `sync()`, so these `info!` calls are already
309	    // suppressed in scripts; we just shape the output here.
310	    if !any_action_needed {
311	        let n = ctxs.len();
312	        let noun = if n == 1 { "repo" } else { "repos" };
313	        info!("sync: {n} {noun}, all bookmarks up-to-date");
314	    } else {
315	        for (repo, stderr) in &fetched {
316	            info!("{}: fetch {}", repo.display(), params.remote);
317	            for line in stderr.lines() {
318	                info!("{line}");
319	            }
320	        }
321	        for ctx in &ctxs {
322	            log_state(&ctx.path, &ctx.state);
323	        }
324	    }
325	
326	    // Phase 3 — act (subprocess output streams through as usual).
327	    // `act_on_state` and `ensure_at_on_main` short-circuit when
328	    // `params.no_check` is false, so check mode is a true no-op here.
329	    for ctx in &ctxs {
330	        act_on_state(ctx, params)?;
331	        ensure_at_on_main(&ctx.path, &params.bookmark, params.no_check)?;
332	    }
333	
334	    // Phase 4 — check mode is fatal when action would be needed.
335	    // Apply mode (`--no-check`) ran the action above and is done.
336	    if !params.no_check && any_action_needed {
337	        let n_action = ctxs
338	            .iter()
339	            .filter(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }))
340	            .count();
341	        let noun = if n_action == 1 { "repo" } else { "repos" };
342	        return Err(format!(
343	            "sync: {n_action} {noun} need action (see above) — \
344	             resolve with `vc-x1 sync --no-check` and re-run"
345	        )
346	        .into());
347	    }
348	    Ok(())
349	}
350	
351	/// Fetch `repo` from `remote` without streaming subprocess output to
352	/// `info!`.
353	///
354	/// Mirrors what `common::run` would do, but returns stderr to the
355	/// caller so the caller can decide whether to surface it (verbose /
356	/// action case) or drop it (clean case). Stdout is dropped — `jj git
357	/// fetch` doesn't use it. Failure carries stderr in the error message.
358	fn fetch_silent(repo: &Path, remote: &str) -> Result<String, Box<dyn std::error::Error>> {
359	    debug!("$ jj git fetch --remote {remote} -R {}", repo.display());
360	    let output = Command::new("jj")
361	        .args(["git", "fetch", "--remote", remote, "-R", &repo_str(repo)])
362	        .output()
363	        .map_err(|e| format!("failed to run jj git fetch: {e}"))?;
364	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
365	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
366	    if !stdout.is_empty() {
367	        debug!("  {stdout}");
368	    }
369	    if !output.status.success() {
370	        return Err(format!("jj git fetch -R {} failed: {stderr}", repo.display()).into());
371	    }
372	    Ok(stderr)
373	}
374	
375	/// Ensure `@` is a descendant of `bookmark`, rebasing if not.
376	///
377	/// `jj git fetch` fast-forwards a tracked local bookmark to the remote
378	/// tip when local is a strict ancestor, but leaves `@` behind — still
379	/// parented on the *pre-fetch* bookmark commit. The `.claude` repo is
380	/// the motivating case: trailing session writes (e.g. `/exit`'s jsonl
381	/// tail) sit in `@`, and without this step they'd end up orphaned on a
382	/// stale branch when the remote advanced.
383	///
384	/// Skipped when `main::@` is already non-empty (i.e., `@` is already
385	/// reachable from `bookmark`). On `--no-check`, runs
386	/// `jj rebase -b @ -d <bookmark>` which carries all commits between
387	/// the old parent and `@` forward, then checks `conflicts()` — any
388	/// conflict in this step trips the outer revert the same way a
389	/// conflicted `act_on_state` rebase would.
390	fn ensure_at_on_main(
391	    repo: &Path,
392	    bookmark: &str,
393	    apply: bool,
394	) -> Result<(), Box<dyn std::error::Error>> {
395	    if revset_nonempty(repo, &format!("{bookmark}::@"))? {
396	        return Ok(());
397	    }
398	    info!("{}: rebasing @ onto '{bookmark}'", repo.display());
399	    if apply {
400	        run(
401	            "jj",
402	            &["rebase", "-b", "@", "-d", bookmark, "-R", &repo_str(repo)],
403	            Path::new("."),
404	        )?;
405	        if has_conflicts(repo)? {
406	            return Err(format!(
407	                "{}: rebase of @ onto '{bookmark}' produced conflicts",
408	                repo.display()
409	            )
410	            .into());
411	        }
412	    }
413	    Ok(())
414	}
415	
416	/// Perform the mutation corresponding to `ctx.state` when `--no-check`.
417	///
418	/// - `UpToDate` / `Ahead` / `NoRemote` → no-op (and no output, the state
419	///   was already logged by `log_state`).
420	/// - `Behind` → `jj bookmark set <b> -r <b>@<remote>` to fast-forward.
421	/// - `Diverged` → `jj rebase -b <b> -d <b>@<remote>`, then probe
422	///   `conflicts()`. A non-empty result means the rebase produced
423	///   conflicted commits; return `Err` so the outer revert restores the
424	///   pre-fetch state.
425	fn act_on_state(ctx: &RepoCtx, params: &SyncParams) -> Result<(), Box<dyn std::error::Error>> {
426	    let repo = &ctx.path;
427	    let remote_rev = format!("{}@{}", params.bookmark, params.remote);
428	    match &ctx.state {
429	        State::UpToDate | State::Ahead { .. } | State::NoRemote => Ok(()),
430	        State::Behind { .. } => {
431	            if params.no_check {
432	                info!("{}: fast-forwarding '{}'", repo.display(), params.bookmark);
433	                run(
434	                    "jj",
435	                    &[
436	                        "bookmark",
437	                        "set",
438	                        &params.bookmark,
439	                        "-r",
440	                        &remote_rev,
441	                        "-R",
442	                        &repo_str(repo),
443	                    ],
444	                    Path::new("."),
445	                )?;
446	            }
447	            Ok(())
448	        }
449	        State::Diverged { local, remote } => {
450	            if params.no_check {
451	                // `local` is either a single commit id or a comma-joined list
452	                // of heads when the bookmark is conflicted. Pick the head
453	                // that isn't the remote — that's the local-only tip. The
454	                // comma-joined path covers the jj post-fetch divergence
455	                // shape (local bookmark conflicted between old local head
456	                // and freshly-fetched remote head).
457	                let local_head = local
458	                    .split(',')
459	                    .find(|h| *h != remote)
460	                    .unwrap_or(local.as_str());
461	                info!(
462	                    "{}: rebasing {local_head} onto {remote_rev}",
463	                    repo.display()
464	                );
465	                run(
466	                    "jj",
467	                    &[
468	                        "rebase",
469	                        "-b",
470	                        local_head,
471	                        "-d",
472	                        &remote_rev,
473	                        "-R",
474	                        &repo_str(repo),
475	                    ],
476	                    Path::new("."),
477	                )?;
478	                if has_conflicts(repo)? {
479	                    return Err(format!("{}: rebase produced conflicts", repo.display()).into());
480	                }
481	            }
482	            Ok(())
483	        }
484	    }
485	}
486	
487	/// Print a single-line summary of `state` at `info!` level.
488	fn log_state(repo: &Path, state: &State) {
489	    let r = repo.display();
490	    match state {
491	        State::UpToDate => info!("{r}: up-to-date"),
492	        State::NoRemote => info!("{r}: no remote counterpart — skipping"),
493	        State::Ahead { local, remote } => {
494	            info!("{r}: ahead (local {local} > remote {remote}); nothing to sync")
495	        }
496	        State::Behind { local, remote } => {
497	            info!("{r}: behind (local {local} < remote {remote}); would fast-forward")
498	        }
499	        State::Diverged { local, remote } => {
500	            info!("{r}: diverged (local {local} vs remote {remote}); would rebase")
501	        }
502	    }
503	}
504	
505	/// Return the id of the most recent operation on `repo`.
506	///
507	/// Used as the revert target on failure. Exposed at `pub(crate)` so
508	/// `push` (0.37.0-2+) can reuse the same snapshot pattern for its
509	/// commit-stage rollback without duplicating the jj invocation.
510	pub(crate) fn current_op_id(repo: &Path) -> Result<String, Box<dyn std::error::Error>> {
511	    let out = run(
512	        "jj",
513	        &[
514	            "op",
515	            "log",
516	            "--no-graph",
517	            "-n",
518	            "1",
519	            "-T",
520	            "id.short(12)",
521	            "-R",
522	            &repo_str(repo),
523	        ],
524	        Path::new("."),
525	    )?;
526	    Ok(out.trim().to_string())
527	}
528	
529	/// Restore `repo` to the operation identified by `op_id`.
530	///
531	/// Thin wrapper around `jj op restore`. Called during the failure
532	/// revert path — drops the caller's returned stdout. Exposed at
533	/// `pub(crate)` so `push` reuses the same restore call.
534	pub(crate) fn op_restore(repo: &Path, op_id: &str) -> Result<(), Box<dyn std::error::Error>> {
535	    run(
536	        "jj",
537	        &["op", "restore", op_id, "-R", &repo_str(repo)],
538	        Path::new("."),
539	    )?;
540	    Ok(())
541	}
542	
543	/// Classify the relationship between `bookmark` and `bookmark@remote`.
544	///
545	/// Uses `bookmarks(<b>)` rather than the bare name so a conflicted
546	/// bookmark (jj's representation of a diverged fetch) resolves to all
547	/// of its heads instead of erroring. When the set has multiple heads,
548	/// the bookmark is conflicted and the repo is `Diverged` by definition.
549	/// Otherwise we compare the single local head against the single
550	/// remote commit via two revset-ancestry probes.
551	///
552	/// Returns `NoRemote` when `<b>@<remote>` does not resolve — the caller
553	/// logs a skip and moves on.
554	fn classify(
555	    repo: &Path,
556	    bookmark: &str,
557	    remote: &str,
558	) -> Result<State, Box<dyn std::error::Error>> {
559	    let local_heads = local_bookmark_heads(repo, bookmark)?;
560	    let remote_rev = format!("{bookmark}@{remote}");
561	    let Some(remote) = try_commit_id(repo, &remote_rev)? else {
562	        return Ok(State::NoRemote);
563	    };
564	    if local_heads.is_empty() {
565	        return Err(format!("{}: bookmark '{bookmark}' does not exist", repo.display()).into());
566	    }
567	    if local_heads.len() > 1 {
568	        // Conflicted bookmark — jj's shape for post-fetch divergence.
569	        let local = local_heads.join(",");
570	        return Ok(State::Diverged { local, remote });
571	    }
572	    let local = local_heads.into_iter().next().unwrap(); // OK: `len() > 1` arm handled above, `is_empty()` handled above
573	    if local == remote {
574	        return Ok(State::UpToDate);
575	    }
576	    let local_is_anc = revset_nonempty(repo, &format!("{local}::{remote_rev}"))?;
577	    let remote_is_anc = revset_nonempty(repo, &format!("{remote_rev}::{local}"))?;
578	    Ok(match (local_is_anc, remote_is_anc) {
579	        (true, _) => State::Behind { local, remote },
580	        (false, true) => State::Ahead { local, remote },
581	        (false, false) => State::Diverged { local, remote },
582	    })
583	}
584	
585	/// Return all commit ids the `bookmark` currently points at.
586	///
587	/// Normally a one-element vector; two or more elements indicate a
588	/// conflicted bookmark (jj's representation of diverged post-fetch
589	/// state, where the local bookmark has multiple heads).
590	fn local_bookmark_heads(
591	    repo: &Path,
592	    bookmark: &str,
593	) -> Result<Vec<String>, Box<dyn std::error::Error>> {
594	    let out = run(
595	        "jj",
596	        &[
597	            "log",
598	            "-r",
599	            &format!("bookmarks(exact:{bookmark})"),
600	            "--no-graph",
601	            "-T",
602	            r#"commit_id.short(12) ++ "\n""#,
603	            "-R",
604	            &repo_str(repo),
605	        ],
606	        Path::new("."),
607	    )?;
608	    Ok(out
609	        .lines()
610	        .map(|l| l.trim().to_string())
611	        .filter(|l| !l.is_empty())
612	        .collect())
613	}
614	
615	/// Return the short commit id that `rev` resolves to in `repo`.
616	///
617	/// Errors when the revset is unresolvable or matches multiple heads
618	/// — callers that want to tolerate "revset doesn't resolve" should use
619	/// `try_commit_id`.
620	fn commit_id(repo: &Path, rev: &str) -> Result<String, Box<dyn std::error::Error>> {
621	    let out = run(
622	        "jj",
623	        &[
624	            "log",
625	            "-r",
626	            rev,
627	            "--no-graph",
628	            "-T",
629	            "commit_id.short(12)",
630	            "-R",
631	            &repo_str(repo),
632	        ],
633	        Path::new("."),
634	    )?;
635	    Ok(out.trim().to_string())
636	}
637	
638	/// Like `commit_id`, but `Ok(None)` when the revset doesn't resolve.
639	///
640	/// jj reports missing revisions via stderr strings like
641	/// `Revision \`foo@origin\` doesn't exist` or `No such revision …`;
642	/// both get mapped to `Ok(None)` so callers can distinguish "missing"
643	/// from "other subprocess failure".
644	fn try_commit_id(repo: &Path, rev: &str) -> Result<Option<String>, Box<dyn std::error::Error>> {
645	    match commit_id(repo, rev) {
646	        Ok(id) if id.is_empty() => Ok(None),
647	        Ok(id) => Ok(Some(id)),
648	        Err(e) => {
649	            let msg = e.to_string();
650	            if msg.contains("doesn't exist") || msg.contains("No such revision") {
651	                Ok(None)
652	            } else {
653	                Err(e)
654	            }
655	        }
656	    }
657	}
658	
659	/// Return `true` when `revset` matches at least one commit in `repo`.
660	fn revset_nonempty(repo: &Path, revset: &str) -> Result<bool, Box<dyn std::error::Error>> {
661	    let out = run(
662	        "jj",
663	        &[
664	            "log",
665	            "-r",
666	            revset,
667	            "--no-graph",
668	            "-T",
669	            r#"commit_id.short() ++ "\n""#,
670	            "-R",
671	            &repo_str(repo),
672	        ],
673	        Path::new("."),
674	    )?;
675	    Ok(!out.trim().is_empty())
676	}
677	
678	/// Return `true` when `repo` has any conflicted commits.
679	fn has_conflicts(repo: &Path) -> Result<bool, Box<dyn std::error::Error>> {
680	    revset_nonempty(repo, "conflicts()")
681	}
682	
683	/// Convert a path to a `String` suitable for passing as a subprocess arg.
684	fn repo_str(p: &Path) -> String {
685	    p.to_string_lossy().into_owned()
686	}
687	
688	#[cfg(test)]
689	mod tests;
690	
691	#[cfg(test)]
692	mod integration_tests;
693

